// Flutter imports:
import 'package:flutter/foundation.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/controllers/locale_controller.dart';
import 'package:baseball_detector_flutter/data/models/user_info.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/utils/environment.dart';
import 'package:baseball_detector_flutter/utils/locale_ext.dart';
import 'package:baseball_detector_flutter/views/hooks/use_launch_url.dart';
import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';

AsyncValueSetter<UserInfo> useContactFormUrl() {
  final ref = useWidgetRef();
  final launchUrl = useLaunchUrl();
  final locale = ref.watch(localeControllerProvider);
  final teamId = ref.watch(profileStorageProvider).getTeamId();
  final baseUrl = locale.isJapanese
      ? Constants.contactFormJaURL
      : Constants.contactFormEnURL;

  return useCallback((UserInfo userInfo) async {
    final _ContactFormQueryParam queryParam;

    if (isDev) {
      queryParam = locale.isJapanese
          ? _ContactFormQueryParam.devJa()
          : _ContactFormQueryParam.devEn();
    } else if (isStg) {
      queryParam = locale.isJapanese
          ? _ContactFormQueryParam.stgJa()
          : _ContactFormQueryParam.stgEn();
    } else {
      queryParam = locale.isJapanese
          ? _ContactFormQueryParam.prdJa()
          : _ContactFormQueryParam.prdEn();
    }

    var urlToLaunch = Uri.https('docs.google.com', baseUrl);

    if (userInfo.profile.username != null &&
        userInfo.email != null &&
        teamId != null) {
      urlToLaunch = Uri.https(
        'docs.google.com',
        baseUrl,
        {
          'usp': 'pp_url',
          queryParam.userName: userInfo.profile.username,
          queryParam.email: userInfo.email,
          queryParam.userId: userInfo.id,
          queryParam.teamId: teamId,
        },
      );
    }

    await launchUrl(urlToLaunch.toString());
  }, [locale, teamId]);
}

class _ContactFormQueryParam {
  const _ContactFormQueryParam._({
    required this.userName,
    required this.email,
    required this.userId,
    required this.teamId,
  });

  final String userName;
  final String email;
  final String userId;
  final String teamId;

  factory _ContactFormQueryParam.devJa() => _ContactFormQueryParam._(
        userName: 'entry.108128219',
        email: 'entry.1606259024',
        userId: 'entry.1164794134',
        teamId: 'entry.1493517610',
      );

  factory _ContactFormQueryParam.devEn() => _ContactFormQueryParam._(
        userName: 'entry.10406628',
        email: 'entry.1874889072',
        userId: 'entry.1100158163',
        teamId: 'entry.1642107795',
      );

  factory _ContactFormQueryParam.stgJa() => _ContactFormQueryParam._(
        userName: 'entry.1784897948',
        email: 'entry.180072029',
        userId: 'entry.1174952172',
        teamId: 'entry.2070392721',
      );

  factory _ContactFormQueryParam.stgEn() => _ContactFormQueryParam._(
        userName: 'entry.2133041275',
        email: 'entry.1885826773',
        userId: 'entry.1660330705',
        teamId: 'entry.1414228537',
      );

  factory _ContactFormQueryParam.prdJa() => _ContactFormQueryParam._(
        userName: 'entry.1032906492',
        email: 'entry.1536256583',
        userId: 'entry.1681068454',
        teamId: 'entry.1887667099',
      );

  factory _ContactFormQueryParam.prdEn() => _ContactFormQueryParam._(
        userName: 'entry.1663092141',
        email: 'entry.1549368548',
        userId: 'entry.2120867320',
        teamId: 'entry.999462204',
      );
}

