/// {@category Containers}
library;

// Dart imports:
import 'dart:async';
import 'dart:math' as math;

// Flutter imports:
import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';
import 'package:licenses_dart/licenses_dart.dart';

// Project imports:
import 'package:baseball_detector_flutter/views/components/custom_loading_indicator.dart';
import 'package:baseball_detector_flutter/views/themes/font_manager.dart';

// ignore: depend_on_referenced_packages

/// Page that displays license analysis and deduplication features
class LicenseCheckerPage extends HookWidget {
  const LicenseCheckerPage({super.key});

  @override
  Widget build(BuildContext context) {
    // Use streaming for progressive loading
    final licenseStream = useMemoized(
      () => LicenseChecker.instance.analyzeLicensesStream(),
    );

    final searchQuery = useState('');
    final selectedLicenseType = useState<String?>(null);
    final currentData = useState<
        ({List<UniqueLicenseInfo> uniqueLicenses, LicenseStats stats})?>(null);
    final isLoading = useState(true);
    final error = useState<String?>(null);

    // Listen to the stream
    useEffect(() {
      final subscription = licenseStream.listen(
        (data) {
          currentData.value = data;
          isLoading.value = false;
        },
        onError: (e) {
          error.value = e.toString();
          isLoading.value = false;
        },
      );

      return subscription.cancel;
    }, [licenseStream]);

    if (isLoading.value) {
      return Scaffold(
        body: CustomScrollView(
          slivers: [
            const SliverAppBar(
              title: Text('License Checker'),
              floating: true,
              snap: true,
            ),
            const SliverFillRemaining(
              child: Center(child: CustomLoadingIndicator()),
            ),
          ],
        ),
      );
    }

    if (error.value != null) {
      return Scaffold(
        body: CustomScrollView(
          slivers: [
            const SliverAppBar(
              title: Text('License Checker'),
              floating: true,
              snap: true,
            ),
            SliverFillRemaining(
              child: Center(
                child: Column(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: [
                    const Icon(Icons.error, size: 64, color: Colors.red),
                    const SizedBox(height: 16),
                    Text('Error analyzing licenses: ${error.value}'),
                  ],
                ),
              ),
            ),
          ],
        ),
      );
    }

    final data = currentData.value!;
    final uniqueLicenses = data.uniqueLicenses;
    final stats = data.stats;

    // Filter licenses based on search query with debouncing
    final filteredLicenses = useMemoized(() {
      return searchQuery.value.isEmpty
          ? uniqueLicenses
          : LicenseChecker.instance
              .searchLicenses(uniqueLicenses, searchQuery.value);
    }, [uniqueLicenses, searchQuery.value]);

    return Scaffold(
      body: SafeArea(
        child: CustomScrollView(
          slivers: [
            // SliverAppBar with title
            const SliverAppBar(
              surfaceTintColor: Colors.transparent,
              title: Text('License Checker', style: TextStyleManager.appBar),
              floating: true,
              snap: true,
            ),
            // Statistics Card
            SliverToBoxAdapter(
              child: Card(
                margin: const EdgeInsets.fromLTRB(16, 0, 16, 16),
                child: Padding(
                  padding: const EdgeInsets.all(16),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(
                        'License Analysis',
                        style: TextStyleManager.headline6,
                      ),
                      const Gap(8),
                      Row(
                        mainAxisAlignment: MainAxisAlignment.spaceAround,
                        children: [
                          _StatItem(
                            label: 'Total',
                            value: stats.totalLicenses.toString(),
                            color: Colors.blue,
                          ),
                          _StatItem(
                            label: 'Unique',
                            value: stats.uniqueLicenses.toString(),
                            color: Colors.green,
                          ),
                          _StatItem(
                            label: 'Duplicates',
                            value: stats.duplicateCount.toString(),
                            color: Colors.orange,
                          ),
                        ],
                      ),
                    ],
                  ),
                ),
              ),
            ),

            // Search Bar
            SliverToBoxAdapter(
              child: Padding(
                padding: const EdgeInsets.symmetric(horizontal: 16),
                child: _DebouncedSearchField(
                  onChanged: (value) => searchQuery.value = value,
                ),
              ),
            ),

            // Pinned License Type Filter
            _SliverPinnedLicenseFilter(
              licenses: filteredLicenses,
              selectedLicenseType: selectedLicenseType,
            ),

            // License List
            _SliverLicenseList(
              licenses: filteredLicenses,
              selectedLicenseType: selectedLicenseType.value,
            ),
          ],
        ),
      ),
    );
  }
}

/// Pinned license type filter using SliverPersistentHeader
class _SliverPinnedLicenseFilter extends HookWidget {
  const _SliverPinnedLicenseFilter({
    required this.licenses,
    required this.selectedLicenseType,
  });

  final List<UniqueLicenseInfo> licenses;
  final ValueNotifier<String?> selectedLicenseType;

  @override
  Widget build(BuildContext context) {
    // Group licenses by type with caching
    final licenseGroupsFuture = useMemoized(
      () => LicenseChecker.instance.groupLicensesByType(licenses),
      [licenses],
    );

    return SliverPersistentHeader(
      pinned: true,
      delegate: _LicenseFilterDelegate(
        licenseGroupsFuture: licenseGroupsFuture,
        selectedLicenseType: selectedLicenseType,
      ),
    );
  }
}

/// Delegate for the pinned license filter header
class _LicenseFilterDelegate extends SliverPersistentHeaderDelegate {
  const _LicenseFilterDelegate({
    required this.licenseGroupsFuture,
    required this.selectedLicenseType,
  });

  final Future<Map<String, List<UniqueLicenseInfo>>> licenseGroupsFuture;
  final ValueNotifier<String?> selectedLicenseType;

  @override
  double get minExtent => 60.0;

  @override
  double get maxExtent => 60.0;

  @override
  bool shouldRebuild(covariant SliverPersistentHeaderDelegate oldDelegate) {
    return oldDelegate != this;
  }

  @override
  Widget build(
    BuildContext context,
    double shrinkOffset,
    bool overlapsContent,
  ) {
    return Container(
      color: Theme.of(context).scaffoldBackgroundColor,
      child: FutureBuilder<Map<String, List<UniqueLicenseInfo>>>(
        future: licenseGroupsFuture,
        builder: (context, snapshot) {
          if (snapshot.hasError) {
            return Center(
              child: Text(
                'Error loading filters',
                style: TextStyle(color: Colors.red[600]),
              ),
            );
          }

          final licenseGroups = snapshot.data ?? {};

          if (licenseGroups.isEmpty) {
            return const Center(child: SizedBox(height: 20, width: 20));
          }

          return Container(
            height: 60,
            padding: const EdgeInsets.symmetric(vertical: 8),
            child: ListView(
              scrollDirection: Axis.horizontal,
              padding: const EdgeInsets.symmetric(horizontal: 16),
              children: [
                ValueListenableBuilder<String?>(
                  valueListenable: selectedLicenseType,
                  builder: (context, selected, _) => FilterChip(
                    label: const Text('All'),
                    selected: selected == null,
                    onSelected: (_) => selectedLicenseType.value = null,
                  ),
                ),
                const SizedBox(width: 8),
                ...licenseGroups.keys.map((type) => Padding(
                      padding: const EdgeInsets.only(right: 8),
                      child: ValueListenableBuilder<String?>(
                        valueListenable: selectedLicenseType,
                        builder: (context, selected, _) => FilterChip(
                          label: Text('$type (${licenseGroups[type]!.length})'),
                          selected: selected == type,
                          onSelected: (_) => selectedLicenseType.value =
                              selected == type ? null : type,
                        ),
                      ),
                    )),
              ],
            ),
          );
        },
      ),
    );
  }
}

/// Sliver license list widget
class _SliverLicenseList extends HookWidget {
  const _SliverLicenseList({
    required this.licenses,
    required this.selectedLicenseType,
  });

  final List<UniqueLicenseInfo> licenses;
  final String? selectedLicenseType;

  @override
  Widget build(BuildContext context) {
    // Group licenses by type with caching
    final licenseGroupsFuture = useMemoized(
      () => LicenseChecker.instance.groupLicensesByType(licenses),
      [licenses],
    );

    return FutureBuilder<Map<String, List<UniqueLicenseInfo>>>(
      future: licenseGroupsFuture,
      builder: (context, snapshot) {
        if (snapshot.connectionState == ConnectionState.waiting) {
          return const SliverToBoxAdapter(
            child: SizedBox(
              height: 200,
              child: Center(child: CustomLoadingIndicator()),
            ),
          );
        }

        if (snapshot.hasError) {
          return SliverToBoxAdapter(
            child: SizedBox(
              height: 200,
              child: Center(
                child: Text('Error loading licenses: ${snapshot.error}'),
              ),
            ),
          );
        }

        final licenseGroups = snapshot.data ?? {};
        final licensesToShow = selectedLicenseType == null
            ? licenses
            : (licenseGroups[selectedLicenseType] ?? []);

        return _LicenseListView(licenses: licensesToShow);
      },
    );
  }
}

/// Optimized license list view using SliverList for better performance
class _LicenseListView extends HookWidget {
  const _LicenseListView({
    required this.licenses,
  });

  final List<UniqueLicenseInfo> licenses;

  @override
  Widget build(BuildContext context) {
    // Simplified caching - only cache visible items
    final licenseTypesCache = useState<Map<int, String>>({});

    return SliverList.builder(
      itemCount: licenses.length,
      itemBuilder: (context, index) {
        final license = licenses[index];

        return _OptimizedLicenseCard(
          license: license,
          index: index,
          licenseTypesCache: licenseTypesCache,
        );
      },
    );
  }
}

/// Debounced search field for better performance
class _DebouncedSearchField extends HookWidget {
  const _DebouncedSearchField({required this.onChanged});

  final ValueChanged<String> onChanged;

  @override
  Widget build(BuildContext context) {
    final controller = useTextEditingController();
    final debounceTimer = useRef<Timer?>(null);

    return TextField(
      controller: controller,
      decoration: const InputDecoration(
        hintText: 'Search licenses or packages...',
        prefixIcon: Icon(Icons.search),
        border: OutlineInputBorder(),
        contentPadding: EdgeInsets.symmetric(horizontal: 16),
      ),
      onChanged: (value) {
        // Cancel previous timer
        debounceTimer.value?.cancel();

        // Set new timer with 300ms delay
        debounceTimer.value = Timer(const Duration(milliseconds: 300), () {
          onChanged(value);
        });
      },
    );
  }
}

/// Optimized license card with lazy loading and better performance
class _OptimizedLicenseCard extends HookWidget {
  const _OptimizedLicenseCard({
    required this.license,
    required this.index,
    required this.licenseTypesCache,
  });

  final UniqueLicenseInfo license;
  final int index;
  final ValueNotifier<Map<int, String>> licenseTypesCache;

  @override
  Widget build(BuildContext context) {
    // Track license type loading state
    final licenseType = useState<String?>(null);
    final isLoading = useState(false);

    // Load license type on demand when widget becomes visible
    useEffect(() {
      if (licenseTypesCache.value.containsKey(index)) {
        licenseType.value = licenseTypesCache.value[index]!;
        return null;
      }

      // Load license type asynchronously
      if (licenseType.value == null && !isLoading.value) {
        isLoading.value = true;

        LicenseChecker.instance
            .detectLicenseType(license.licenseText, license.packages)
            .then((type) {
          if (context.mounted) {
            licenseType.value = type;

            // Update cache
            final newCache = Map<int, String>.from(licenseTypesCache.value);
            newCache[index] = type;
            licenseTypesCache.value = newCache;

            isLoading.value = false;
          }
        }).catchError((e) {
          if (context.mounted) {
            licenseType.value = 'Unknown';
            isLoading.value = false;
          }
        });
      }

      return null;
    }, [index]);

    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 4),
      child: Card(
        child: ExpansionTile(
          title: Text(
            licenseType.value ?? (isLoading.value ? 'Loading...' : 'Unknown'),
            style: const TextStyle(fontWeight: FontWeight.bold),
            overflow: TextOverflow.ellipsis,
          ),
          subtitle: Text(
            '${license.packages.length} packages: ${license.packages.take(3).join(", ")}${license.packages.length > 3 ? "..." : ""}',
            maxLines: 1,
            overflow: TextOverflow.ellipsis,
          ),
          children: [
            _LazyLicenseDetails(license: license),
          ],
        ),
      ),
    );
  }
}

/// Lazy-loaded license details that only render when expanded
class _LazyLicenseDetails extends HookWidget {
  const _LazyLicenseDetails({required this.license});

  final UniqueLicenseInfo license;

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.all(16),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        mainAxisSize: MainAxisSize.min,
        children: [
          Text(
            'Packages (${license.packages.length}):',
            style: const TextStyle(fontWeight: FontWeight.bold),
          ),
          const SizedBox(height: 8),
          // Virtualized package chips for large lists
          if (license.packages.length > 20)
            _VirtualizedPackageChips(packages: license.packages)
          else
            Flexible(
              child: Wrap(
                spacing: 4,
                runSpacing: 4,
                children: license.packages
                    .map((pkg) => Chip(
                          label:
                              Text(pkg, style: const TextStyle(fontSize: 12)),
                          materialTapTargetSize:
                              MaterialTapTargetSize.shrinkWrap,
                        ))
                    .toList(),
              ),
            ),
          const SizedBox(height: 16),
          // License text header with copy button
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              const Text(
                'License Text:',
                style: TextStyle(fontWeight: FontWeight.bold),
              ),
              IconButton(
                icon: const Icon(Icons.copy, size: 20),
                onPressed: () => _copyLicenseText(context, license.licenseText),
                tooltip: 'Copy license text to clipboard',
                padding: EdgeInsets.zero,
                constraints: const BoxConstraints(
                  minWidth: 32,
                  minHeight: 32,
                ),
              ),
            ],
          ),
          const SizedBox(height: 8),
          Container(
            width: double.infinity,
            constraints: const BoxConstraints(
              maxHeight: 200,
              minHeight: 100,
            ),
            padding: const EdgeInsets.all(12),
            decoration: BoxDecoration(
              color: Colors.grey[100],
              borderRadius: BorderRadius.circular(8),
            ),
            child: SingleChildScrollView(
              child: Text(
                license.licenseText,
                style: const TextStyle(
                  fontFamily: 'monospace',
                  fontSize: 12,
                ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  /// Copy license text to clipboard with user feedback
  Future<void> _copyLicenseText(
      BuildContext context, String licenseText) async {
    try {
      await Clipboard.setData(ClipboardData(text: licenseText));

      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            content: Text('License text copied to clipboard'),
            duration: Duration(seconds: 2),
            behavior: SnackBarBehavior.floating,
          ),
        );
      }
    } catch (e) {
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Failed to copy: $e'),
            duration: const Duration(seconds: 3),
            behavior: SnackBarBehavior.floating,
            backgroundColor: Colors.red,
          ),
        );
      }
    }
  }
}

/// Virtualized package chips for large package lists
