                label: Text('+$remainingCount more',
                    style: const TextStyle(
                        fontSize: 12, fontStyle: FontStyle.italic)),
                materialTapTargetSize: MaterialTapTargetSize.shrinkWrap,
                backgroundColor: Colors.grey[300],
              ),
          ],
        ),
      ],
    );
  }
}

