/// Service class for analyzing and deduplicating license information
class LicenseChecker {
  LicenseChecker._();

  /// Singleton instance
  static final LicenseChecker _instance = LicenseChecker._();
  static LicenseChecker get instance => _instance;

  /// Cache for license type detection results
  final Map<String, String> _licenseTypeCache = {};

  /// Cache for SPDX template matching results
  final Map<String, String?> _spdxCache = {};

  /// Cache for normalized license texts
  final Map<String, String> _normalizedTextCache = {};

  /// Preloaded SPDX licenses for instant access
  final Map<String, License> _preloadedSpdxLicenses = {};
  bool _spdxPreloaded = false;

  /// Optimized: License template index for fast filtering
  final Map<String, Set<String>> _licenseKeywordIndex = {};
  final Map<String, int> _licenseWordCounts = {};
  final Map<String, Set<String>> _licenseSignatures = {};
  bool _indexBuilt = false;

  /// Analyzes all licenses and returns deduplicated results with statistics
  Future<({List<UniqueLicenseInfo> uniqueLicenses, LicenseStats stats})>
      analyzeLicenses() async {
    final licenses = <LicenseEntry>[];

    // Collect all license entries
    await for (final license in LicenseRegistry.licenses) {
      licenses.add(license);
    }

    return _processLicenses(licenses);
  }

  /// Streaming version for progressive loading and better UX
  Stream<({List<UniqueLicenseInfo> uniqueLicenses, LicenseStats stats})>
      analyzeLicensesStream() async* {
    // Preload SPDX licenses in background
    _preloadSpdxLicensesAsync();

    final licenses = <LicenseEntry>[];
    const batchSize = 20; // Smaller batches for faster initial display

    await for (final license in LicenseRegistry.licenses) {
      licenses.add(license);

      // Emit intermediate results more frequently for better perceived performance
      if (licenses.length % batchSize == 0) {
        yield _processLicenses(licenses);
        // Minimal delay to keep UI responsive
        await Future.delayed(Duration.zero);
      }
    }

    // Final result
    yield _processLicenses(licenses);
  }

  /// Preloads SPDX licenses asynchronously for instant access with indexing
  Future<void> _preloadSpdxLicensesAsync() async {
    if (_spdxPreloaded) return;

    final totalLicenses = _getComprehensiveSpdxLicenses().length;
    debugPrint('🚀 SPDX: Loading $totalLicenses license templates...');

    try {
      // Load licenses in parallel batches for faster loading
      final licenseIds = _getComprehensiveSpdxLicenses();
      final batchSize = 10;
      final futures = <Future<Map<String, License>>>[];

      for (int i = 0; i < licenseIds.length; i += batchSize) {
        final batch = licenseIds.skip(i).take(batchSize).toList();
        futures.add(compute(_loadSpdxLicensesInIsolate, batch));
      }

      final results = await Future.wait(futures);
      for (final result in results) {
        _preloadedSpdxLicenses.addAll(result);
      }

      // Build search index for fast filtering
      await _buildLicenseIndex();

      _spdxPreloaded = true;
      debugPrint(
          '✅ SPDX: ${_preloadedSpdxLicenses.length} templates loaded with index');
    } catch (e) {
      // Fallback to main thread if isolate fails
      var loadedCount = 0;
      for (final licenseId in _getComprehensiveSpdxLicenses()) {
        try {
          _preloadedSpdxLicenses[licenseId] = License(licenseId);
          loadedCount++;
        } catch (e) {
          // Skip invalid licenses
          continue;
        }
      }
      await _buildLicenseIndex();
      _spdxPreloaded = true;
      debugPrint('✅ SPDX: $loadedCount templates loaded (fallback) with index');
    }
  }

  /// Builds optimized search index for fast license filtering
  Future<void> _buildLicenseIndex() async {
    if (_indexBuilt) return;

    debugPrint('🔍 Building license search index...');

    for (final entry in _preloadedSpdxLicenses.entries) {
      final licenseId = entry.key;
      final licenseText = _getCachedNormalizedText(entry.value.licenseText);

      // Build keyword index for fast filtering
      final words =
          licenseText.split(RegExp(r'\s+')).where((w) => w.length > 2).toSet();
      _licenseKeywordIndex[licenseId] = words;
      _licenseWordCounts[licenseId] = words.length;

      // Build signature index (most distinctive words)
      final signature = _extractLicenseSignature(licenseText);
      _licenseSignatures[licenseId] = signature;
    }

    _indexBuilt = true;
    debugPrint(
        '✅ License index built for ${_preloadedSpdxLicenses.length} templates');
  }

  /// Extracts distinctive signature words from license text
  Set<String> _extractLicenseSignature(String text) {
    final words = text.split(RegExp(r'\s+')).where((w) => w.length > 3);

    // Common words to exclude from signature
    const commonWords = {
      'software',
      'license',
      'copyright',
      'permission',
      'notice',
      'conditions',
      'limitation',
      'liability',
      'warranty',
      'damages',
      'authors',
      'holders',
      'granted',
      'subject',
      'following',
      'including',
      'without',
      'provided'
    };

    // Extract distinctive words (not too common, not too rare)
    final wordFreq = <String, int>{};
    for (final word in words) {
      if (!commonWords.contains(word)) {
        wordFreq[word] = (wordFreq[word] ?? 0) + 1;
      }
    }

    // Return top distinctive words as signature
    final sortedWords = wordFreq.entries.toList()
      ..sort((a, b) => b.value.compareTo(a.value));

    return sortedWords.take(10).map((e) => e.key).toSet();
  }

  /// Processes license entries and removes duplicates with optimized performance
  ({List<UniqueLicenseInfo> uniqueLicenses, LicenseStats stats})
      _processLicenses(List<LicenseEntry> licenses) {
    final licenseMap = <String, UniqueLicenseInfo>{};
    var totalCount = 0;

    for (final license in licenses) {
      totalCount++;

      // Convert paragraphs to text for comparison
      final licenseText =
          license.paragraphs.map((p) => p.text).join('\n').trim();

      // Use cached normalized text for better performance
      final normalizedText = _getCachedNormalizedText(licenseText);

      if (licenseMap.containsKey(normalizedText)) {
        // Merge packages for existing license
        final existing = licenseMap[normalizedText]!;
        final mergedPackages = <String>{
          ...existing.packages,
          ...license.packages,
        }.toList()
          ..sort();

        licenseMap[normalizedText] = UniqueLicenseInfo(
          licenseText: existing.licenseText,
          packages: mergedPackages,
          paragraphs: existing.paragraphs,
        );
      } else {
        // Add new unique license
        licenseMap[normalizedText] = UniqueLicenseInfo(
          licenseText: licenseText,
          packages: List<String>.from(license.packages)..sort(),
          paragraphs: license.paragraphs.toList(),
        );
      }
    }

    final uniqueLicenses = licenseMap.values.toList();

    // Sort by number of packages (most used first)
    uniqueLicenses
        .sort((a, b) => b.packages.length.compareTo(a.packages.length));

    final stats = LicenseStats(
      totalLicenses: totalCount,
      uniqueLicenses: uniqueLicenses.length,
      duplicateCount: totalCount - uniqueLicenses.length,
      mostUsedLicense: uniqueLicenses.isNotEmpty ? uniqueLicenses.first : null,
    );

    return (uniqueLicenses: uniqueLicenses, stats: stats);
  }

  /// Gets cached normalized text or computes and caches it
  String _getCachedNormalizedText(String text) {
    final key = text.hashCode.toString();
    if (_normalizedTextCache.containsKey(key)) {
      return _normalizedTextCache[key]!;
    }

    final normalized = _normalizeLicenseText(text);
    _normalizedTextCache[key] = normalized;
    return normalized;
  }

  /// Normalizes license text for better duplicate detection
  String _normalizeLicenseText(String text) {
    return text
        // Remove extra whitespace
        .replaceAll(RegExp(r'\s+'), ' ')
        // Remove common variations in copyright years
        .replaceAll(
            RegExp(r'Copyright \(c\) \d{4}(-\d{4})?'), 'Copyright (c) YEAR')
        .replaceAll(RegExp(r'Copyright \d{4}(-\d{4})?'), 'Copyright YEAR')
        // Normalize line endings
        .replaceAll(RegExp(r'\r\n|\r'), '\n')
        // Remove trailing/leading whitespace
        .trim()
        // Convert to lowercase for case-insensitive comparison
        .toLowerCase();
  }

  /// Searches for licenses containing specific text
  List<UniqueLicenseInfo> searchLicenses(
    List<UniqueLicenseInfo> licenses,
    String query,
  ) {
    if (query.isEmpty) return licenses;

    final lowerQuery = query.toLowerCase();
    return licenses.where((license) {
      return license.packages
              .any((pkg) => pkg.toLowerCase().contains(lowerQuery)) ||
          license.licenseText.toLowerCase().contains(lowerQuery);
    }).toList();
  }

  /// Groups licenses by their type with optimized batch processing
  Future<Map<String, List<UniqueLicenseInfo>>> groupLicensesByType(
    List<UniqueLicenseInfo> licenses,
  ) async {
    final groups = <String, List<UniqueLicenseInfo>>{};

    // Process licenses in parallel batches for better performance
    const batchSize = 20;
    final futures = <Future<void>>[];

    for (int i = 0; i < licenses.length; i += batchSize) {
      final batch = licenses.skip(i).take(batchSize).toList();

      futures.add(_processBatchForGrouping(batch, groups));

      // Limit concurrent batches to avoid overwhelming the system
      if (futures.length >= 5) {
        await Future.wait(futures);
        futures.clear();
      }
    }

    // Wait for remaining batches
    if (futures.isNotEmpty) {
      await Future.wait(futures);
    }

    return groups;
  }

  /// Process a batch of licenses for grouping
  Future<void> _processBatchForGrouping(
    List<UniqueLicenseInfo> batch,
    Map<String, List<UniqueLicenseInfo>> groups,
  ) async {
    for (final license in batch) {
      final type =
          await detectLicenseType(license.licenseText, license.packages);
      groups.putIfAbsent(type, () => []).add(license);
    }
  }

  /// Optimized SPDX-only license type detection with staged filtering
  Future<String> detectLicenseType(String text, List<String> packages) async {
    // Check cache first for performance
    final cacheKey = text.hashCode.toString();
    if (_licenseTypeCache.containsKey(cacheKey)) {
      return _licenseTypeCache[cacheKey]!;
    }

    // Use optimized SPDX template matching with staged filtering
    final spdxLicense = await _detectFromSpdxTemplatesOptimized(text);
    final result = spdxLicense ?? 'Unknown';

    // Cache the result
    _licenseTypeCache[cacheKey] = result;

    return result;
  }

  /// Highly optimized SPDX template matching with staged filtering
  Future<String?> _detectFromSpdxTemplatesOptimized(String text) async {
    final normalizedText = _getCachedNormalizedText(text);
    final cacheKey = normalizedText.hashCode.toString();

    // Check SPDX cache
    if (_spdxCache.containsKey(cacheKey)) {
      return _spdxCache[cacheKey];
    }

    try {
      // Ensure index is built
      if (!_indexBuilt && _spdxPreloaded) {
        await _buildLicenseIndex();
      }

      if (!_spdxPreloaded || _preloadedSpdxLicenses.isEmpty) {
        debugPrint(
            '⚠️ SPDX: Templates not ready, falling back to basic detection');
        _spdxCache[cacheKey] = null;
        return null;
      }

      // Stage 1: Fast signature-based filtering
      final candidates = _filterBySignature(normalizedText);
      if (candidates.isEmpty) {
        _spdxCache[cacheKey] = null;
        return null;
      }

      debugPrint(
          '🔍 SPDX: Filtered to ${candidates.length} candidates from ${_preloadedSpdxLicenses.length} templates');

      // Stage 2: Word count filtering (quick elimination)
      final textWords = normalizedText
          .split(RegExp(r'\s+'))
          .where((w) => w.length > 2)
          .toSet();
      final wordCountFiltered = candidates.where((licenseId) {
        final templateWordCount = _licenseWordCounts[licenseId] ?? 0;
        final ratio = textWords.length / templateWordCount;
        return ratio >= 0.3 && ratio <= 3.0; // Allow reasonable size variation
      }).toList();

      if (wordCountFiltered.isEmpty) {
        _spdxCache[cacheKey] = null;
        return null;
      }

      // Stage 3: Jaccard similarity on filtered candidates
      double bestSimilarity = 0.0;
      String? bestMatch;

      for (final licenseId in wordCountFiltered) {
        final templateWords = _licenseKeywordIndex[licenseId] ?? <String>{};
        final similarity =
            _calculateJaccardSimilarityOptimized(textWords, templateWords);

        if (similarity > bestSimilarity) {
          bestSimilarity = similarity;
          bestMatch = licenseId;
        }

        // Early exit for very good matches
        if (similarity > 0.95) {
          debugPrint(
              '🎯 SPDX: Found excellent match $licenseId (${(similarity * 100).toStringAsFixed(1)}%)');
          break;
        }
      }

      // Return match only if similarity is above threshold
      final result = (bestSimilarity >= 0.75) ? bestMatch : null;

      if (result != null) {
        debugPrint(
            '✅ SPDX: Matched $result (${(bestSimilarity * 100).toStringAsFixed(1)}%)');
      }

      _spdxCache[cacheKey] = result;
      return result;
    } catch (e) {
      debugPrint('❌ SPDX: Error in detection: $e');
      _spdxCache[cacheKey] = null;
      return null;
    }
  }

  /// Fast signature-based filtering to reduce candidate set
  List<String> _filterBySignature(String text) {
    if (!_indexBuilt) return _preloadedSpdxLicenses.keys.toList();

    final textSignature = _extractLicenseSignature(text);
    if (textSignature.isEmpty) return _preloadedSpdxLicenses.keys.toList();

    final candidates = <String>[];

    for (final entry in _licenseSignatures.entries) {
      final licenseId = entry.key;
      final licenseSignature = entry.value;

      // Calculate signature overlap
      final overlap = textSignature.intersection(licenseSignature);
      final minSignatureSize =
          math.min(textSignature.length, licenseSignature.length);

      if (minSignatureSize > 0) {
        final overlapRatio = overlap.length / minSignatureSize;

        // Include if there's reasonable signature overlap
        if (overlapRatio >= 0.2) {
          candidates.add(licenseId);
        }
      }
    }

    return candidates.isNotEmpty
        ? candidates
        : _preloadedSpdxLicenses.keys.toList();
  }

  /// Optimized Jaccard similarity calculation for pre-computed word sets
  double _calculateJaccardSimilarityOptimized(
      Set<String> words1, Set<String> words2) {
    if (words1.isEmpty && words2.isEmpty) return 1.0;
    if (words1.isEmpty || words2.isEmpty) return 0.0;

    // Use more efficient set operations
    final intersectionSize = words1.intersection(words2).length;
    final unionSize = words1.length + words2.length - intersectionSize;

    return intersectionSize / unionSize;
  }

  /// Returns comprehensive list of SPDX license identifiers for maximum coverage
  List<String> _getComprehensiveSpdxLicenses() {
    // Expanded list covering most common and important licenses
    return [
      // Most common permissive licenses
      'MIT',
      'Apache-2.0',
      'BSD-3-Clause',
      'BSD-2-Clause',
      'BSD-1-Clause',
      'ISC',
      'BSL-1.0',

      // GPL family
      'GPL-3.0-only',
      'GPL-3.0-or-later',
      'GPL-2.0-only',
      'GPL-2.0-or-later',
      'GPL-1.0-only',
      'GPL-1.0-or-later',

      // LGPL family
      'LGPL-3.0-only',
      'LGPL-3.0-or-later',
      'LGPL-2.1-only',
      'LGPL-2.1-or-later',
      'LGPL-2.0-only',
      'LGPL-2.0-or-later',

      // AGPL family
      'AGPL-3.0-only',
      'AGPL-3.0-or-later',
      'AGPL-1.0-only',
      'AGPL-1.0-or-later',

      // Mozilla Public License
      'MPL-2.0',
      'MPL-1.1',
      'MPL-1.0',

      // Creative Commons
      'CC0-1.0',
      'CC-BY-4.0',
      'CC-BY-SA-4.0',
      'CC-BY-NC-4.0',
      'CC-BY-3.0',
      'CC-BY-SA-3.0',

      // Other important licenses
      'Unlicense',
      'WTFPL',
      'Zlib',
      'Artistic-2.0',
      'EPL-2.0',
      'EPL-1.0',
      'CDDL-1.0',
      'CDDL-1.1',
      'CPL-1.0',
      'IPL-1.0',
      'MS-PL',
      'MS-RL',
      'OFL-1.1',
      'PostgreSQL',
      'Python-2.0',
      'Ruby',
      'Vim',
      'X11',
      'NCSA',
      'OpenSSL',
      'SSLeay',
      'Beerware',
      'EUPL-1.2',
      'EUPL-1.1',
      'AFL-3.0',
      'OSL-3.0',
      'CECILL-2.1',
      'LPPL-1.3c',
      'GFDL-1.3-only',
      'GFDL-1.2-only',
      'GFDL-1.1-only',
    ];
  }

  /// Clears all caches to free memory
  void clearCache() {
    _licenseTypeCache.clear();
    _spdxCache.clear();
    _normalizedTextCache.clear();
    _preloadedSpdxLicenses.clear();
    _licenseKeywordIndex.clear();
    _licenseWordCounts.clear();
    _licenseSignatures.clear();
    _spdxPreloaded = false;
    _indexBuilt = false;
  }
}

/// Isolate function to load SPDX licenses in background
Map<String, License> _loadSpdxLicensesInIsolate(List<String> licenseIds) {
  final licenses = <String, License>{};
  for (final licenseId in licenseIds) {
    try {
      licenses[licenseId] = License(licenseId);
    } catch (e) {
      // Skip invalid licenses
      continue;
    }
  }
  return licenses;
}

/// Represents unique license information with packages that use it
class UniqueLicenseInfo {
  const UniqueLicenseInfo({
    required this.licenseText,
    required this.packages,
    required this.paragraphs,
  });

  /// The text content of the license
  final String licenseText;

  /// List of packages that use this license
  final List<String> packages;

  /// The formatted paragraphs of the license
  final List<LicenseParagraph> paragraphs;

  /// Creates a hash for the license text to identify duplicates
  String get licenseHash => licenseText.hashCode.toString();

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is UniqueLicenseInfo &&
          runtimeType == other.runtimeType &&
          licenseText == other.licenseText;

  @override
  int get hashCode => licenseText.hashCode;

  @override
  String toString() =>
      'UniqueLicenseInfo(packages: $packages, hash: $licenseHash)';
}

/// Statistics about license analysis
class LicenseStats {
  const LicenseStats({
    required this.totalLicenses,
    required this.uniqueLicenses,
    required this.duplicateCount,
    required this.mostUsedLicense,
  });

  /// Total number of license entries before deduplication
  final int totalLicenses;

  /// Number of unique licenses after deduplication
  final int uniqueLicenses;

  /// Number of duplicate licenses removed
  final int duplicateCount;

  /// The license used by the most packages
  final UniqueLicenseInfo? mostUsedLicense;

  /// Percentage of duplicates
  double get duplicatePercentage =>
      totalLicenses > 0 ? (duplicateCount / totalLicenses) * 100 : 0.0;

  @override
  String toString() =>
      'LicenseStats(total: $totalLicenses, unique: $uniqueLicenses, duplicates: $duplicateCount)';
}

